pages.css:
* { box-sizing: border-box; margin: 0; padding: 0; }
.page {
  width: 1242px;
  height: 1660px;
  background-color: #F4F5F7;
  color: #1A1A1A;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  padding: 100px 96px;
  display: flex;
  flex-direction: column;
  letter-spacing: 0;
  position: relative;
}

.header {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 120px;
}

.icon {
  font-size: 42px;
}

.label {
  font-size: 38px;
  font-weight: 600;
  color: #555;
}

.title-section {
  margin-bottom: 140px;
}

.page-title p {
  font-size: 136px;
  font-weight: 900;
  line-height: 1.25;
  color: #111;
  letter-spacing: 0;
}

.page-title .highlight-title {
  color: #D32F2F;
}

.proof-list {
  display: flex;
  flex-direction: column;
  gap: 64px;
  flex: 1;
}

.proof-item {
  display: flex;
  flex-direction: column;
  gap: 20px;
  border-top: 3px solid #E0E2E6;
  padding-top: 32px;
}

.proof-tag {
  font-size: 38px;
  font-weight: 800;
  color: #D32F2F;
}

.proof-text {
  font-size: 44px;
  line-height: 1.6;
  color: #333;
  font-weight: 400;
}

