.page-04 { width: 1242px; height: 1660px; background-color: #F6F6F4; box-sizing: border-box; padding: 100px 96px; position: relative; display: flex; flex-direction: column; font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", sans-serif; letter-spacing: 0; }
.header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 48px; }
.label { font-size: 38px; color: #666; font-weight: 600; }
.icon { font-size: 46px; }
.title { font-size: 104px; font-weight: 900; line-height: 1.25; color: #111; margin-bottom: 56px; }
.title p { margin: 0; }
.metric-box { background-color: #FFF; border: 3px solid #111; border-radius: 12px; padding: 40px 48px; margin-bottom: 56px; box-shadow: 8px 8px 0px #111; }
.metric-value { font-size: 104px; font-weight: 900; color: #D94A38; line-height: 1.1; margin-bottom: 16px; }
.metric-value span { font-size: 56px; font-weight: 800; margin-left: 8px; color: #D94A38; }
.metric-sub { font-size: 40px; color: #444; line-height: 1.5; font-weight: 600; }
.proof-list { display: flex; flex-direction: column; border-top: 3px solid #111; }
.proof-item { display: flex; padding: 36px 0; border-bottom: 1px solid #D0D0D0; align-items: flex-start; }
.proof-item:last-child { border-bottom: none; }
.proof-tag { width: 180px; font-size: 40px; font-weight: 800; color: #111; flex-shrink: 0; line-height: 1.6; }
.proof-tag::before { content: ""; display: inline-block; width: 12px; height: 12px; background-color: #D94A38; border-radius: 50%; margin-right: 12px; position: relative; top: -4px; }
.proof-text { font-size: 38px; line-height: 1.6; color: #333; flex-grow: 1; font-weight: 400; }
.footnote { position: absolute; bottom: 88px; left: 96px; right: 96px; font-size: 34px; color: #888; line-height: 1.5; border-left: 4px solid #D94A38; padding-left: 20px; }

.page-05 {
  width: 1242px;
  height: 1660px;
  box-sizing: border-box;
  background-color: #F8F9FA;
  padding: 100px 100px;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  color: #1A1A1A;
  display: flex;
  flex-direction: column;
}

.header {
  margin-bottom: 80px;
}

.label {
  display: flex;
  align-items: center;
  gap: 16px;
  font-size: 38px;
  color: #666666;
  font-weight: 500;
}

.title-section {
  margin-bottom: 80px;
}

.page-title {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.title-line {
  font-size: 112px;
  font-weight: 900;
  line-height: 1.1;
  letter-spacing: 0;
  color: #111111;
}

.sub-item-section {
  margin-bottom: 100px;
  background: #FFFFFF;
  padding: 48px;
  border-radius: 16px;
  border-left: 8px solid #111111;
  box-shadow: 0 20px 40px rgba(0,0,0,0.03);
}

.sub-item {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.sub-tag {
  align-self: flex-start;
  font-size: 38px;
  font-weight: 700;
  color: #FFFFFF;
  background-color: #111111;
  padding: 8px 24px;
  border-radius: 8px;
}

.sub-text {
  font-size: 42px;
  line-height: 1.6;
  color: #333333;
  margin: 0;
}

.steps-section {
  display: flex;
  flex-direction: column;
  gap: 40px;
  flex: 1;
}

.step-item {
  display: flex;
  align-items: flex-start;
  gap: 40px;
  padding-bottom: 40px;
  border-bottom: 2px solid #E5E5E5;
}

.step-item:last-child {
  border-bottom: none;
  padding-bottom: 0;
}

.step-number {
  font-size: 64px;
  font-weight: 900;
  color: #999999;
  line-height: 1;
  padding-top: 6px;
}

.step-content {
  flex: 1;
}

.step-text {
  font-size: 44px;
  line-height: 1.5;
  color: #444444;
  margin: 0;
  font-weight: 500;
}

.step-text strong {
  font-weight: 800;
  color: #111111;
}

.page-06 {
  width: 1242px;
  height: 1660px;
  background-color: #101010;
  color: #FFFFFF;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  box-sizing: border-box;
  padding: 100px 96px;
  display: flex;
  flex-direction: column;
  position: relative;
  letter-spacing: 0;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 180px;
}

.header-icon {
  font-size: 40px;
}

.header-label {
  font-size: 38px;
  color: #888888;
  font-weight: 600;
}

.title-section {
  flex: 1;
}

.page-title {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.title-line {
  font-size: 120px;
  font-weight: 900;
  line-height: 1.2;
  margin: 0;
  color: #FFFFFF;
}

.title-line.highlight {
  color: #FF4444;
}

.action-section {
  display: flex;
  flex-direction: column;
  gap: 40px;
  margin-bottom: 40px;
}

.action-item {
  display: flex;
  flex-direction: column;
  gap: 24px;
  background: #1A1A1A;
  padding: 48px;
  border-radius: 16px;
  border-left: 8px solid #FF4444;
}

.action-tag {
  display: inline-flex;
  font-size: 34px;
  background: rgba(255, 68, 68, 0.15);
  color: #FF4444;
  padding: 10px 20px;
  border-radius: 8px;
  font-weight: 700;
  align-self: flex-start;
}

.action-text {
  font-size: 42px;
  line-height: 1.6;
  color: #CCCCCC;
  margin: 0;
  font-weight: 400;
}
